sp_widget.client_script:
function citizenRedirectCtrl($scope, $window, $timeout) {
    /* widget controller */
    var c = this;

    c.isRedirecting = false;

    // 1. GUEST SESSION HANDLING: Re-route the registration button
    if (!c.data.shouldRedirect) {

        $timeout(function() {
            // Target the button pointing to the bad 'register_profile' ID
            var regButtons = document.querySelectorAll('a[href*="register_profile"], .btn-register, [href*="register_profile"]');

            if (regButtons.length > 0) {
                regButtons.forEach(function(btn) {
                    // Overwrite it to point directly to your working citizen signup page
                    btn.setAttribute('href', '/sp?id=citizen_signup');
                });
            }
        }, 300);

        return;
    }

    // 2. LOGGED-IN CITIZEN REDIRECT (Working flawlessly)
    if (c.data.shouldRedirect) {
        var targetCatalogUrl = "/sp?id=sc_category&sys_id=d9b010c1c3d98790c5d75242b401316c";

        if ($window.location.href.indexOf('d9b010c1c3d98790c5d75242b401316c') === -1) {
            c.isRedirecting = true;
            $window.location.href = targetCatalogUrl;
        }
    }
}

sp_widget.css:
.redirect-overlay {
   position: fixed;
   top: 0;
   left: 0;
   width: 100vw;
   height: 100vh;
   background: #ffffff;
   z-index: 9999;
   display: flex;
   justify-content: center;
   align-items: center;
}

sp_widget.script:
(function() {
    /* populate the 'data' object */
    /* e.g., data.table = $sp.getValue('table'); */

    // Check if the session user is logged in and is NOT an admin
    var currentUser = gs.getUser();

    if (gs.isLoggedIn() && currentUser.getName() !== 'admin') {
        data.shouldRedirect = true;
    } else {
        data.shouldRedirect = false;
    }
})();
